bash -c "./cli/bin/ctl list tickets --limit 30 --format json | python3 -c \"
import json, sys
from datetime import datetime

data = json.load(sys.stdin)

# Group by ISO week and status
weeks = {}
for t in data:
    dt = datetime.fromisoformat(t['created_at'].replace('Z','+00:00'))
    wk = dt.strftime('%Y-W%W')  # Monday-based week number
    if wk not in weeks:
        weeks[wk] = {'total': 0, 'escalated': 0}
    weeks[wk]['total'] += 1
    if t['status'] == 'escalated':
        weeks[wk]['escalated'] += 1

for wk in sorted(weeks):
    print(f'{wk}: total={weeks[wk][\"total\"]}, escalated={weeks[wk][\"escalated\"]}')
\""

